from __future__ import annotations

import operator
import sys

OPS: dict[str, callable] = {
    "+": operator.add,
    "-": operator.sub,
    "*": operator.mul,
    "/": operator.truediv,
}


def evaluate(expression: str) -> float:
    """Evaluate a simple 'a op b' expression."""
    parts = expression.strip().split()
    if len(parts) != 3:
        raise ValueError(f"Expected 'a op b', got: {expression!r}")

    left_str, op_str, right_str = parts

    try:
        left = float(left_str)
        right = float(right_str)
    except ValueError:
        raise ValueError(f"Invalid numbers: {left_str!r}, {right_str!r}")

    if op_str not in OPS:
        raise ValueError(f"Unknown operator: {op_str!r}. Supported: {', '.join(OPS)}")

    if op_str == "/" and right == 0:
        raise ZeroDivisionError("Division by zero")

    return OPS[op_str](left, right)


def main() -> None:
    if len(sys.argv) > 1:
        expr = " ".join(sys.argv[1:])
    else:
        expr = input("Expression: ")

    try:
        result = evaluate(expr)
        print(f"{result:g}")
    except (ValueError, ZeroDivisionError) as e:
        print(f"Error: {e}", file=sys.stderr)
        sys.exit(1)


if __name__ == "__main__":
    main()
