from __future__ import annotations

import json
from dataclasses import asdict, dataclass, field
from datetime import datetime
from pathlib import Path


@dataclass
class Task:
    """A single task item."""
    title: str
    done: bool = False
    created: str = field(default_factory=lambda: datetime.now().isoformat())


class TaskManager:
    """Manages a list of tasks with JSON persistence."""

    def __init__(self, path: Path | str = "tasks.json") -> None:
        self._path = Path(path)
        self._tasks: list[Task] = []
        self._load()

    def _load(self) -> None:
        if self._path.exists():
            data = json.loads(self._path.read_text())
            self._tasks = [Task(**item) for item in data]

    def save(self) -> None:
        self._path.write_text(json.dumps([asdict(t) for t in self._tasks], indent=2))

    def add(self, title: str) -> Task:
        task = Task(title=title)
        self._tasks.append(task)
        self.save()
        return task

    def complete(self, index: int) -> None:
        if 0 <= index < len(self._tasks):
            self._tasks[index].done = True
            self.save()
        else:
            raise IndexError(f"No task at index {index}")

    def pending(self) -> list[Task]:
        return [t for t in self._tasks if not t.done]

    def completed(self) -> list[Task]:
        return [t for t in self._tasks if t.done]

    @property
    def all(self) -> list[Task]:
        return list(self._tasks)

